// src/draggableNode.js
const labelMap = {
  inputNode: "Input",
  textNode: "Text",
  llmNode: "LLM",
  outputNode: "Output",
  deleteNode: "Delete",
};

export const DraggableNode = ({ type }) => {
  const onDragStart = (event, nodeType) => {
    const appData = {
      nodeType,
      className: nodeType === "deleteNode" ? "delete-node" : "",
      data:
        nodeType === "deleteNode"
          ? {
              candidates: [],
              onDelete: () => {},
              canDeleteTool: false,
              label: labelMap[nodeType],
            }
          : {
              label: labelMap[nodeType] || nodeType,
            },
    };

    event.dataTransfer.setData("application/reactflow", JSON.stringify(appData));
    event.dataTransfer.effectAllowed = "move";
    event.target.style.cursor = "grabbing";
  };

  return (
    <div
      className={type}
      onDragStart={(event) => onDragStart(event, type)}
      onDragEnd={(event) => (event.target.style.cursor = "grab")}
      style={{
        cursor: "grab",
        minWidth: "80px",
        height: "60px",
        display: "flex",
        alignItems: "center",
        borderRadius: "8px",
        backgroundColor: "#1C2536",
        justifyContent: "center",
        flexDirection: "column",
      }}
      draggable
    >
      <span style={{ color: "#fff" }}>{labelMap[type] || type}</span>
    </div>
  );
};
